+        let ts = timestamp.format("%Y-%m-%dT%H:%M:%S%.3fZ");
+        let line = if use_color() {
+            let reset = "\x1b[0m";
+            let color = level.color_code();
+            format!("[{ts}] [{color}{level}{reset}] [{test_name}] {message}")
+        } else {
+            format!("[{ts}] [{level}] [{test_name}] {message}")
+        };
+
+        eprintln!("{line}");
+        write_to_file(&strip_ansi(&line));
+    }
+}
